const { Client, LocalAuth } = require('whatsapp-web.js');
const QRCode = require('qrcode');
const express = require('express');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());

const activeSessions = new Map();

const verifyApiSecret = (req, res, next) => {
  const apiSecret = req.headers['x-api-secret'];
    if (!apiSecret || apiSecret !== process.env.API_SECRET) {
        return res.status(401).json({ error: 'Unauthorized' });
          }
            next();
            };

            async function notifySupabase(userId, status, phoneNumber, qrCode, pairingCode) {
              try {
                  const supabaseUrl = process.env.SUPABASE_WEBHOOK_URL;
                      const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

                          if (!supabaseUrl || !supabaseKey) {
                                console.warn('Supabase credentials not configured, skipping notification');
                                      return;
                                          }

                                              const response = await fetch(supabaseUrl, {
                                                    method: 'POST',
                                                          headers: {
                                                                  'Content-Type': 'application/json',
                                                                          'Authorization': `Bearer ${supabaseKey}`
                                                                                },
                                                                                      body: JSON.stringify({
                                                                                              userId,
                                                                                                      status,
                                                                                                              phoneNumber,
                                                                                                                      qrCode,
                                                                                                                              pairingCode,
                                                                                                                                      timestamp: new Date().toISOString()
                                                                                                                                            })
                                                                                                                                                });

                                                                                                                                                    if (!response.ok) {
                                                                                                                                                          console.error('Failed to notify Supabase:', response.status, await response.text());
                                                                                                                                                              } else {
                                                                                                                                                                    console.log(`Supabase notified: ${status} for user ${userId}`);
                                                                                                                                                                        }
                                                                                                                                                                          } catch (err) {
                                                                                                                                                                              console.error('Error notifying Supabase:', err);
                                                                                                                                                                                }
                                                                                                                                                                                }

                                                                                                                                                                                // Route principale pour creer une session
                                                                                                                                                                                app.post('/session/create', verifyApiSecret, async (req, res) => {
                                                                                                                                                                                  const { userId, connectionMethod = 'qr_code', phoneNumber } = req.body;

                                                                                                                                                                                    console.log(`Creating ${connectionMethod} session for user ${userId}`);

                                                                                                                                                                                      // Verifier si une session existe deja
                                                                                                                                                                                        if (activeSessions.has(userId)) {
                                                                                                                                                                                            const existingClient = activeSessions.get(userId);

                                                                                                                                                                                                // Si deja connecte, retourner l'info
                                                                                                                                                                                                    if (existingClient.info) {
                                                                                                                                                                                                          return res.json({
                                                                                                                                                                                                                  sessionId: userId,
                                                                                                                                                                                                                          status: 'connected',
                                                                                                                                                                                                                                  phoneNumber: existingClient.info.wid.user
                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                // Session en cours, rejeter
                                                                                                                                                                                                                                                    return res.status(400).json({
                                                                                                                                                                                                                                                          error: 'Session already in progress',
                                                                                                                                                                                                                                                                message: 'Please wait for current session initialization'
                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                        // Creer le client WhatsApp
                                                                                                                                                                                                                                                                          const client = new Client({
                                                                                                                                                                                                                                                                              authStrategy: new LocalAuth({
                                                                                                                                                                                                                                                                                    clientId: userId,
                                                                                                                                                                                                                                                                                          dataPath: './sessions'
                                                                                                                                                                                                                                                                                              }),
                                                                                                                                                                                                                                                                                                  puppeteer: {
                                                                                                                                                                                                                                                                                                        headless: true,
                                                                                                                                                                                                                                                                                                              args: [
                                                                                                                                                                                                                                                                                                                      '--no-sandbox',
                                                                                                                                                                                                                                                                                                                              '--disable-setuid-sandbox',
                                                                                                                                                                                                                                                                                                                                      '--disable-dev-shm-usage',
                                                                                                                                                                                                                                                                                                                                              '--disable-accelerated-2d-canvas',
                                                                                                                                                                                                                                                                                                                                                      '--no-first-run',
                                                                                                                                                                                                                                                                                                                                                              '--no-zygote',
                                                                                                                                                                                                                                                                                                                                                                      '--single-process',
                                                                                                                                                                                                                                                                                                                                                                              '--disable-gpu'
                                                                                                                                                                                                                                                                                                                                                                                    ]
                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                          });

                                                                                                                                                                                                                                                                                                                                                                                            activeSessions.set(userId, client);

                                                                                                                                                                                                                                                                                                                                                                                              let qrGenerated = false;
                                                                                                                                                                                                                                                                                                                                                                                                let pairingCodeGenerated = false;

                                                                                                                                                                                                                                                                                                                                                                                                  // Handler pour QR Code
                                                                                                                                                                                                                                                                                                                                                                                                    client.on('qr', async (qr) => {
                                                                                                                                                                                                                                                                                                                                                                                                        if (connectionMethod === 'qr_code' && !qrGenerated) {
                                                                                                                                                                                                                                                                                                                                                                                                              console.log(`QR Code generated for user ${userId}`);

                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                            const qrDataUrl = await QRCode.toDataURL(qr);
                                                                                                                                                                                                                                                                                                                                                                                                                                    const responseQrCode = qrDataUrl;
                                                                                                                                                                                                                                                                                                                                                                                                                                            qrGenerated = true;

                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Notifier Supabase du QR
                                                                                                                                                                                                                                                                                                                                                                                                                                                            await notifySupabase(userId, 'qr_pending', null, qrDataUrl, null);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          console.error('QR generation error:', err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Handler quand le client est pret
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          client.on('ready', async () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.log(`Client ready for user ${userId}`);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const phoneNumber = client.info.wid.user;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      console.log(`Connected phone: ${phoneNumber}`);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Notifier Supabase de la connexion reussie
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              await notifySupabase(userId, 'connected', phoneNumber, null, null);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // Handler pour deconnexion
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    client.on('disconnected', async (reason) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        console.log(`Client disconnected for user ${userId}:`, reason);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            activeSessions.delete(userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await notifySupabase(userId, 'disconnected', null, null, null);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Handler pour erreurs d'authentification
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      client.on('auth_failure', async (msg) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          console.error(`Auth failure for user ${userId}:`, msg);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              activeSessions.delete(userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  await notifySupabase(userId, 'auth_failure', null, null, null);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await client.initialize();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (connectionMethod === 'pairing_code') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // PAIRING CODE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (!phoneNumber) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  client.destroy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          activeSessions.delete(userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return res.status(400).json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            error: 'phoneNumber is required for pairing code method'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const code = await client.requestPairingCode(phoneNumber);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                pairingCodeGenerated = true;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        console.log(`Pairing code generated for user ${userId}: ${code}`);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Notifier Supabase du pairing code
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        await notifySupabase(userId, 'pairing_code_pending', phoneNumber, null, code);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                res.json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          sessionId: userId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    status: 'pairing_code_pending',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              pairingCode: code,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        phoneNumber: phoneNumber
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.error('Pairing code error:', err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      client.destroy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              activeSessions.delete(userId);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return res.status(500).json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                error: 'Failed to generate pairing code',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          message: err.message
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // QR CODE
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Attendre que le QR soit genere
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              await new Promise((resolve, reject) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const timeout = setTimeout(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                reject(new Error('QR code generation timeout'));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }, 30000); // 30 secondes max

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const checkQr = setInterval(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (qrGenerated) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      clearInterval(checkQr);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  clearTimeout(timeout);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              resolve(true);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }, 1000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.json(responseData);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      console.error('Session creation error:', error);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Nettoyer en cas d'erreur
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (req.body.userId) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const client = activeSessions.get(req.body.userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (client) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await client.destroy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    } catch (e) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.error('Error destroying client:', e);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              activeSessions.delete(req.body.userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.status(500).json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  error: 'Session creation failed',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        message: error.message
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Route pour deconnecter une session
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              app.post('/session/disconnect', verifyApiSecret, async (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const { userId } = req.body;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const client = activeSessions.get(userId);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!client) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return res.json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          success: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  message: 'No active session to disconnect'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await client.destroy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    activeSessions.delete(userId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        await notifySupabase(userId, 'disconnected', null, null, null);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  success: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        message: 'Session disconnected successfully'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  console.error('Disconnect error:', error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      res.status(500).json({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            error: 'Failed to disconnect',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  message: error.message
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        app.get('/health', (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          res.json({ status: 'ok', timestamp: new Date().toISOString() });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          app.listen(PORT, () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            console.log(`Le service WhatsApp Cloud est exécuté sur le port ${PORT}.`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });